use super::file::{FileHandle, FileOps, OpenFlags, FileMode, SeekFrom};
use super::Stat;
use crate::memory::ept::EptManager;
use alloc::boxed::Box;
use alloc::vec::Vec;

const PROC_VERSION: &[u8] = b"Linux version 6.1.0-aether (aether@hyperion) (gcc version 12.2.0) #1 SMP\n";
const PROC_CMDLINE: &[u8] = b"BOOT_IMAGE=/boot/kernel.bin root=/dev/ram0 console=ttyS0\n";

fn copy_content(buf: &mut [u8], content: &[u8]) -> usize {
    let len = core::cmp::min(buf.len(), content.len());
    buf[..len].copy_from_slice(&content[..len]);
    len
}

pub struct ProcVersion;

impl FileOps for ProcVersion {
    fn read(&mut self, buf: &mut [u8], _ept: &EptManager) -> Result<usize, i64> {
        Ok(copy_content(buf, PROC_VERSION))
    }

    fn write(&mut self, _buf: &[u8], _ept: &EptManager) -> Result<usize, i64> {
        Err(-crate::vm::syscall::linux::EACCES)
    }

    fn lseek(&mut self, _offset: i64, _whence: SeekFrom) -> Result<u64, i64> {
        Ok(0)
    }

    fn fstat(&mut self, stat_buf: &mut Stat, _ept: &EptManager) -> Result<(), i64> {
        stat_buf.st_dev = 0x3;
        stat_buf.st_ino = 0x1001;
        stat_buf.st_mode = 0o444 | 0o010000;
        stat_buf.st_nlink = 1;
        stat_buf.st_uid = 0;
        stat_buf.st_gid = 0;
        stat_buf.st_rdev = 0;
        stat_buf.st_size = 80;
        stat_buf.st_blksize = 4096;
        stat_buf.st_blocks = 8;
        stat_buf.st_atime = 0;
        stat_buf.st_atime_nsec = 0;
        stat_buf.st_mtime = 0;
        stat_buf.st_mtime_nsec = 0;
        stat_buf.st_ctime = 0;
        stat_buf.st_ctime_nsec = 0;
        Ok(())
    }

    fn clone(&self) -> Box<dyn FileOps> {
        Box::new(ProcVersion)
    }
}

