fn append_line(dest: &mut Vec<u8>, label: &[u8], value: &[u8]) {
    dest.extend_from_slice(label);
    dest.extend_from_slice(value);
    dest.push(b'\n');
}

pub struct ProcCpuinfo;

impl FileOps for ProcCpuinfo {
    fn read(&mut self, buf: &mut [u8], _ept: &EptManager) -> Result<usize, i64> {
        let mut content = Vec::with_capacity(512);
        
        append_line(&mut content, b"processor\t: ", b"0");
        append_line(&mut content, b"vendor_id\t: ", b"GenuineIntel");
        append_line(&mut content, b"cpu family\t: ", b"6");
        append_line(&mut content, b"model\t\t: ", b"142");
        append_line(&mut content, b"model name\t: ", b"Intel(R) Core(TM) i7-8700K CPU @ 3.70GHz");
        append_line(&mut content, b"stepping\t: ", b"10");
        append_line(&mut content, b"cpu MHz\t\t: ", b"3700.000");
        append_line(&mut content, b"cache size\t: ", b"12288 KB");
        append_line(&mut content, b"physical id\t: ", b"0");
        append_line(&mut content, b"siblings\t: ", b"12");
        append_line(&mut content, b"core id\t\t: ", b"0");
        append_line(&mut content, b"cpu cores\t: ", b"6");
        append_line(&mut content, b"fpu\t\t: ", b"yes");
        append_line(&mut content, b"fpu_exception\t: ", b"yes");
        append_line(&mut content, b"cpuid level\t: ", b"22");
        append_line(&mut content, b"wp\t\t: ", b"yes");
        append_line(&mut content, b"flags\t\t: ", b"fpu vme de pse tsc msr pae mce cx8 apic sep mtrr pge mca cmov pat pse36 clflush dts acpi mmx fxsr sse sse2 ss ht tm pbe syscall nx pdpe1gb rdtscp lm constant_tsc art arch_perfmon pebs bts rep_good nopl xtopology nonstop_tsc cpuid aperfmperf pni pclmulqdq dtes64 monitor ds_cpl vmx smx est tm2 ssse3 sdbg fma cx16 xtpr pdcm pcid sse4_1 sse4_2 x2apic movbe popcnt tsc_deadline_timer aes xsave avx f16c rdrand lahf_lm abm 3dnowprefetch cpuid_fault epb invpcid_single pti ssbd ibrs ibpb stibp tpr_shadow vnmi flexpriority ept vpid ept_ad fsgsbase tsc_adjust bmi1 avx2 smep bmi2 erms invpcid mpx rdseed adx smap clflushopt intel_pt xsaveopt xsavec xgetbv1 xsaves dtherm ida arat pln pts hwp hwp_notify hwp_act_window hwp_epp md_clear flush_l1d");
        append_line(&mut content, b"vmx flags\t: ", b"vnmi preemption_timer invvpid ept_x_only ept_ad ept_1gb flexpriority tsc_offset vtpr mtf vapic ept vpid unrestricted_guest ple pml ept_mode_based_exec");
        append_line(&mut content, b"bugs\t\t: ", b"cpu_meltdown spectre_v1 spectre_v2 spec_store_bypass l1tf mds swapgs itlb_multihit srbds");
        append_line(&mut content, b"bogomips\t: ", b"7400.00");
        append_line(&mut content, b"clflush size\t: ", b"64");
        append_line(&mut content, b"cache_alignment\t: ", b"64");
        append_line(&mut content, b"address sizes\t: ", b"39 bits physical, 48 bits virtual");
        content.push(b'\n');
        
        Ok(copy_content(buf, &content))
    }

    fn write(&mut self, _buf: &[u8], _ept: &EptManager) -> Result<usize, i64> {
        Err(-crate::vm::syscall::linux::EACCES)
    }

    fn lseek(&mut self, _offset: i64, _whence: SeekFrom) -> Result<u64, i64> {
        Ok(0)
    }

    fn fstat(&mut self, stat_buf: &mut Stat, _ept: &EptManager) -> Result<(), i64> {
        stat_buf.st_dev = 0x3;
        stat_buf.st_ino = 0x1003;
        stat_buf.st_mode = 0o444 | 0o010000;
        stat_buf.st_nlink = 1;
        stat_buf.st_uid = 0;
        stat_buf.st_gid = 0;
        stat_buf.st_rdev = 0;
        stat_buf.st_size = 2048;
        stat_buf.st_blksize = 4096;
        stat_buf.st_blocks = 8;
        stat_buf.st_atime = 0;
        stat_buf.st_atime_nsec = 0;
        stat_buf.st_mtime = 0;
        stat_buf.st_mtime_nsec = 0;
        stat_buf.st_ctime = 0;
        stat_buf.st_ctime_nsec = 0;
        Ok(())
    }

    fn clone(&self) -> Box<dyn FileOps> {
        Box::new(ProcCpuinfo)
    }
}

